  18→// ── Cluster mode: fork one worker per CPU core ──
  19→// Set CLUSTER_ENABLED=true in production to use all CPU cores.
  20→// Disabled by default so local dev / single-core hosts work without surprises.
  21→const CLUSTER_ENABLED = process.env.CLUSTER_ENABLED === 'true';
  22→const WORKER_COUNT = parseInt(process.env.WORKER_COUNT, 10) || os.cpus().length;
  23→
  24→if (CLUSTER_ENABLED && cluster.isPrimary) {
  25→    console.log(`Primary ${process.pid} starting ${WORKER_COUNT} workers...`);
  26→    for (let i = 0; i < WORKER_COUNT; i++) {
  27→        cluster.fork();
  28→    }
  29→    cluster.on('exit', (worker, code, signal) => {
  30→        console.warn(`Worker ${worker.process.pid} exited (code=${code}, signal=${signal}). Restarting...`);
  31→        cluster.fork();
  32→    });
  33→    // Primary does nothing else — workers handle all requests
  34→} else {
  35→// ── Worker (or non-clustered) process: run Express ──
