 175→const getRequestOrigin = (req) => {
 176→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 177→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 178→    const host = forwardedHost || req.get('host') || '';
 179→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 180→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 181→        ? forwardedProto
 182→        : requestProtocol === 'http' || requestProtocol === 'https'
 183→            ? requestProtocol
 184→            : 'https';
 185→
 186→    if (!host) {
 187→        return SITE_URL;
 188→    }
 189→
 190→    return `${protocol}://${host}`;
 191→};
