 329→const resolveAbsoluteHttpUrl = (rawUrl) => {
 330→    try {
 331→        const raw = String(rawUrl || '').trim();
 332→        if (!raw) return null;
 333→
 334→        const isSupabasePath =
 335→            raw.startsWith('/storage/v1/object/public/')
 336→            || raw.startsWith('storage/v1/object/public/');
 337→
 338→        const baseUrl = isSupabasePath && SUPABASE_URL
 339→            ? `${SUPABASE_URL}/`
 340→            : SITE_URL;
 341→
 342→        const parsed = new URL(raw, baseUrl);
 343→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 344→            return null;
 345→        }
 346→        return parsed.toString();
 347→    } catch {
 348→        return null;
 349→    }
 350→};
