 352→const isPrivateIpv4Address = (ip) => {
 353→    const parts = ip.split('.').map((part) => Number(part));
 354→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
 355→        return true;
 356→    }
 357→
 358→    const [a, b] = parts;
 359→    if (a === 10 || a === 127 || a === 0) return true;
 360→    if (a === 169 && b === 254) return true;
 361→    if (a === 172 && b >= 16 && b <= 31) return true;
 362→    if (a === 192 && b === 168) return true;
 363→    return false;
 364→};
 365→
 366→const isPrivateIpv6Address = (ip) => {
 367→    const normalized = ip.toLowerCase();
 368→    return (
 369→        normalized === '::1' ||
 370→        normalized.startsWith('fc') ||
 371→        normalized.startsWith('fd') ||
 372→        normalized.startsWith('fe80:')
 373→    );
 374→};
 375→
 376→const isPrivateIpAddress = (ip) => {
 377→    const ipVersion = net.isIP(ip);
 378→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
 379→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
 380→    return true;
 381→};
