 509→const convertToOgJpeg = async (inputBuffer) => {
 510→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
 511→        .rotate()
 512→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
 513→            fit: 'contain',
 514→            background: { r: 255, g: 255, b: 255, alpha: 1 },
 515→        })
 516→        .jpeg({ quality: 82, mozjpeg: true })
 517→        .toBuffer();
 518→};
