 830→app.get('/share/post/:journalId/image', async (req, res) => {
 831→    const { journalId } = req.params;
 832→    await ensureShareFonts();
 833→    const debugMode = isShareImageDebugRequest(req);
 834→    const debugPayload = {
 835→        ok: false,
 836→        fallback: false,
 837→        journalId,
 838→        stage: 'start',
 839→        reason: '',
 840→        meta: {
 841→            imageCandidateSource: null,
 842→            imageCandidateRaw: null,
 843→            imageCandidateResolved: null,
 844→            upstreamFinalUrl: null,
 845→            upstreamContentType: null,
 846→            upstreamBytes: null,
 847→            outputBytes: null,
 848→        },
 849→    };
 850→
 851→    const fallbackWithReason = (reason) => {
 852→        debugPayload.ok = false;
 853→        debugPayload.fallback = true;
 854→        debugPayload.stage = 'fallback';
 855→        debugPayload.reason = reason;
 856→        if (debugMode) {
 857→            return sendShareImageDebug(res, debugPayload);
 858→        }
 859→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 860→    };
 861→
 862→    try {
 863→        const journal = await getShareJournal(journalId);
 864→        debugPayload.stage = 'journal_loaded';
 865→        if (!journal) {
 866→            return fallbackWithReason('journal_not_found');
 867→        }
 868→
 869→        const shareMeta = buildShareMetaFromJournal(journal);
 870→        debugPayload.stage = 'candidate_extracted';
 871→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 872→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 873→
 874→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 875→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 876→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 877→            return fallbackWithReason(candidateEvaluation.reason);
 878→        }
 879→
 880→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 881→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 882→            return fallbackWithReason('candidate_is_default_fallback');
 883→        }
 884→
 885→        debugPayload.stage = 'fetching_upstream';
 886→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 887→        debugPayload.stage = 'upstream_loaded';
 888→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 889→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 890→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 891→
 892→        debugPayload.stage = 'converting_image';
 893→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 894→        debugPayload.stage = 'converted_image';
 895→        debugPayload.ok = true;
 896→        debugPayload.reason = 'ok';
 897→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 898→
 899→        if (debugMode) {
 900→            return sendShareImageDebug(res, debugPayload);
 901→        }
 902→
 903→        res.set('Content-Type', 'image/jpeg');
 904→        res.set('Cache-Control', 'public, max-age=3600');
 905→        return res.send(ogImageBuffer);
 906→    } catch (err) {
 907→        debugPayload.stage = 'error';
 908→        debugPayload.reason = err?.message || 'unknown_error';
 909→        console.error('share image route error:', err?.message || err);
 910→        return fallbackWithReason(debugPayload.reason);
 911→    }
 912→});
